import{_ as s,o as a,c as n,a0 as r}from"./chunks/framework.DV6pVIgV.js";const h=JSON.parse('{"title":"訊息與佇列：SQS 與 SNS","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/3.md","filePath":"clf-c02/3.md","lastUpdated":1783683951000}'),e={name:"clf-c02/3.md"};function o(i,t,l,d,p,g){return a(),n("div",null,[...t[0]||(t[0]=[r(`<h1 id="訊息與佇列-sqs-與-sns" tabindex="-1">訊息與佇列：SQS 與 SNS <a class="header-anchor" href="#訊息與佇列-sqs-與-sns" aria-label="Permalink to &quot;訊息與佇列：SQS 與 SNS&quot;">​</a></h1><p>當應用程式拆分為多個獨立元件，元件之間需要一種<strong>可靠且互不干擾</strong>的通訊機制——這正是訊息服務解決的核心問題。</p><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>耦合性（Coupling）</strong></p><ul><li><a href="https://ithelp.ithome.com.tw/articles/10363056" target="_blank" rel="noreferrer">iThome：Coupling 耦合</a></li><li><a href="https://medium.com/marklin-hehe/day-05-%E8%80%A6%E5%90%88%E6%80%A7%E4%B8%89%E5%A4%A7%E5%8E%9F%E5%89%87-adp-sdp-sap-3568850ee3d8" target="_blank" rel="noreferrer">Day-05: 耦合性三大原則 ADP、SDP、SAP</a></li></ul></li><li><p><strong>生產者－消費者模式（Producer-Consumer Pattern）</strong></p><ul><li><a href="https://ithelp.ithome.com.tw/articles/10209296" target="_blank" rel="noreferrer">iThome：Day 28 介紹 Producer Consumer 模式</a></li><li><a href="https://medium.com/bucketing/java-concurrency-producer-and-consumer-%E7%94%9F%E7%94%A2%E8%80%85%E6%B6%88%E8%B2%BB%E8%80%85%E6%A8%A1%E5%BC%8F-%E8%A7%A3%E8%80%A6%E5%90%88%E7%9A%84%E6%A5%B5%E8%87%B4-3acd2559d5cc" target="_blank" rel="noreferrer">Medium：Java Concurrency — 生產者消費者模式，解耦合的極致</a></li></ul></li></ul><h2 id="為什麼需要訊息服務" tabindex="-1">為什麼需要訊息服務 <a class="header-anchor" href="#為什麼需要訊息服務" aria-label="Permalink to &quot;為什麼需要訊息服務&quot;">​</a></h2><p>現代應用架構的演進路徑，本質上是一場降低耦合的工程：</p><ul><li><strong>緊耦合（Monolithic）</strong>：所有功能整合在單一應用中，元件之間<strong>直接同步呼叫</strong>。任一元件發生故障，可能引發連鎖反應，導致整體服務中斷。</li><li><strong>鬆耦合（Microservices）</strong>：元件之間透過<strong>非同步訊息</strong>通訊，相互獨立，不直接綁定。</li></ul><p>將元件解耦後，架構獲得兩項關鍵特性：</p><ol><li><strong>故障隔離（Fault Isolation）</strong>：下游元件不可用時，訊息暫存於佇列，待其恢復後繼續處理，<strong>不影響上游的正常運行</strong>。</li><li><strong>負載緩衝（Load Leveling）</strong>：上游流量驟增時，訊息先進入佇列排隊，下游<strong>依自身處理速率逐一消化</strong>，不會因瞬間流量峰值而過載。</li></ol><p>SQS 與 SNS 是實現鬆耦合架構的兩個核心服務。</p><h2 id="以電商「結帳」為例" tabindex="-1">以電商「結帳」為例 <a class="header-anchor" href="#以電商「結帳」為例" aria-label="Permalink to &quot;以電商「結帳」為例&quot;">​</a></h2><p>顧客送出訂單，後端同時觸發兩條路徑：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>① 訂單寫入 SQS 佇列 ──→ 倉儲系統依自身速率逐一取出處理</span></span>
<span class="line"><span>   （一秒湧入萬筆訂單時，佇列作為緩衝，倉儲系統不因此過載）</span></span>
<span class="line"><span>   → 負載緩衝 + 故障隔離</span></span>
<span class="line"><span></span></span>
<span class="line"><span>② 發布「訂單成立」事件至 SNS 主題 ──→ 同時推送給多個下游訂閱者</span></span>
<span class="line"><span>   （寄送確認信、通知財務系統、通知物流）</span></span>
<span class="line"><span>   → 一對多 fan-out</span></span></code></pre></div><p><strong>SQS 處理「單一任務交付單一消費者、確保每則訊息都被處理」；SNS 處理「單一事件同步廣播至多個接收者」。</strong></p><h2 id="amazon-sqs-simple-queue-service" tabindex="-1">Amazon SQS（Simple Queue Service） <a class="header-anchor" href="#amazon-sqs-simple-queue-service" aria-label="Permalink to &quot;Amazon SQS（Simple Queue Service）&quot;">​</a></h2><p>採用<strong>拉取（Pull）模型</strong>：訊息進入佇列排隊，消費者在就緒時主動發起 poll 請求取得訊息，處理完成後才從佇列刪除。這種設計確保<strong>每則訊息至少被處理一次</strong>，且消費者的處理速率不受上游產生速率影響。</p><p><strong>核心機制：</strong></p><table tabindex="0"><thead><tr><th>機制</th><th>說明</th></tr></thead><tbody><tr><td><strong>訊息保留期限</strong></td><td>訊息最長保留 <strong>14 天</strong>（預設 4 天），待消費者取用</td></tr><tr><td><strong>可見性逾時（Visibility Timeout）</strong></td><td>訊息被取出後進入隱藏狀態，防止其他消費者重複領取；處理完成確認後才正式刪除</td></tr><tr><td><strong>死信佇列（Dead-Letter Queue, DLQ）</strong></td><td>訊息達到最大重試次數後仍處理失敗，自動移入 DLQ 隔離，便於後續診斷與排查</td></tr></tbody></table><p><strong>佇列類型：</strong></p><table tabindex="0"><thead><tr><th>類型</th><th>特性</th></tr></thead><tbody><tr><td><strong>Standard</strong></td><td>近乎無限吞吐量；盡力維持順序，允許偶發的亂序與極少數重複訊息</td></tr><tr><td><strong>FIFO（先進先出）</strong></td><td>嚴格保證訊息順序與僅處理一次（Exactly-Once Processing），適用於金融交易等順序敏感場景</td></tr></tbody></table><h2 id="amazon-sns-simple-notification-service" tabindex="-1">Amazon SNS（Simple Notification Service） <a class="header-anchor" href="#amazon-sns-simple-notification-service" aria-label="Permalink to &quot;Amazon SNS（Simple Notification Service）&quot;">​</a></h2><p>採用<strong>發布 / 訂閱（Pub/Sub）模型</strong>：發布者將訊息送至<strong>主題（Topic）</strong>，SNS 立即以<strong>推送（Push）<strong>方式將訊息</strong>同時分發至所有訂閱者</strong>，實現一對多的 fan-out 通訊。</p><p><strong>支援的訂閱者類型：</strong> Email、SMS 簡訊、HTTP/S 端點、AWS Lambda、SQS 佇列、行動裝置推播（APNs / FCM）。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                    ┌─→ Email（寄送訂單確認信）</span></span>
<span class="line"><span>發布者 →[ SNS 主題 ]─┼─→ Lambda（觸發後續自動化流程）</span></span>
<span class="line"><span>                    └─→ SQS 佇列（轉交下游系統非同步處理）</span></span>
<span class="line"><span>        （單一發布，所有訂閱者同步接收）</span></span></code></pre></div><blockquote><p>🚨 看到「<strong>單一事件需同時通知或觸發多個接收者</strong>」→ <strong>SNS</strong>。</p></blockquote><h2 id="sqs-vs-sns-對照" tabindex="-1">SQS vs SNS 對照 <a class="header-anchor" href="#sqs-vs-sns-對照" aria-label="Permalink to &quot;SQS vs SNS 對照&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th><strong>Amazon SQS（佇列）</strong></th><th><strong>Amazon SNS（發布訂閱）</strong></th></tr></thead><tbody><tr><td>通訊模型</td><td>佇列：訊息排隊等候消費</td><td>Pub/Sub：發布即分發至所有訂閱者</td></tr><tr><td>訊息流向</td><td>消費者主動拉取（Poll）</td><td>SNS 主動推送（Push）至訂閱者</td></tr><tr><td>接收者數量</td><td>通常<strong>一個</strong>消費者處理一則訊息</td><td><strong>一對多</strong>，所有訂閱者同時接收</td></tr><tr><td>典型用途</td><td>任務佇列、突發流量緩衝、確保訊息不遺漏</td><td>事件通知（Email/SMS）、一個事件觸發多個下游動作</td></tr></tbody></table><hr><h2 id="fan-out-模式-sns-sqs" tabindex="-1">Fan-out 模式（SNS + SQS） <a class="header-anchor" href="#fan-out-模式-sns-sqs" aria-label="Permalink to &quot;Fan-out 模式（SNS + SQS）&quot;">​</a></h2><p>以 <strong>SNS 將單一事件推送至多個 SQS 佇列</strong>，每個下游系統擁有獨立佇列，<strong>各自按自身速率處理、互不干擾</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                       ┌─→ [SQS] → 倉儲系統</span></span>
<span class="line"><span>訂單成立 →[ SNS 主題 ]──┼─→ [SQS] → 財務系統</span></span>
<span class="line"><span>                       └─→ [SQS] → 數據分析管線</span></span>
<span class="line"><span>   （單次發布；三個佇列各保有一份副本，各自獨立消費）</span></span></code></pre></div><p>為何不讓 SNS 直接推送至各下游系統，而要中間插入 SQS？因為佇列同時提供了<strong>緩衝</strong>與<strong>重試</strong>能力——某個下游暫時不可用時，訊息持續保留在其佇列中，待服務恢復後繼續處理，對其他下游系統完全無影響。</p><h2 id="重點整理" tabindex="-1">重點整理 <a class="header-anchor" href="#重點整理" aria-label="Permalink to &quot;重點整理&quot;">​</a></h2><ul><li><strong>核心區別</strong>：<strong>SQS = 拉取、點對點、一則訊息由一個消費者處理（任務緩衝）</strong>；<strong>SNS = 推送、Pub/Sub、一對多同步分發（事件廣播）</strong>。</li><li>兩者皆為<strong>鬆耦合</strong>架構工具，共同帶來<strong>故障隔離</strong>與<strong>負載緩衝</strong>兩項架構優勢。</li><li><strong>SQS 關鍵細節</strong>：訊息最長保留 14 天；<strong>可見性逾時</strong>防止重複消費；<strong>DLQ</strong> 隔離持續失敗的訊息；<strong>Standard</strong>（高吞吐、盡力排序）vs <strong>FIFO</strong>（嚴格順序、Exactly-Once）。</li><li><strong>SNS 訂閱者</strong>：Email / SMS / HTTP-S / <strong>Lambda</strong> / <strong>SQS</strong> / 行動推播。</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>任務排隊、確保每則訊息都被處理</td><td><strong>SQS</strong></td></tr><tr><td>突發流量湧入，需緩衝避免下游過載</td><td><strong>SQS</strong></td></tr><tr><td>訊息處理順序不可錯亂</td><td><strong>SQS FIFO</strong></td></tr><tr><td>單一訊息同時通知多個接收者</td><td><strong>SNS</strong></td></tr><tr><td>訂單成立後同時通知倉儲、財務、Email</td><td><strong>SNS（fan-out）</strong></td></tr><tr><td>廣播事件且每個下游需獨立緩衝與重試</td><td><strong>SNS + 多個 SQS（fan-out 組合）</strong></td></tr><tr><td>持續處理失敗的訊息需隔離排查</td><td><strong>死信佇列（DLQ）</strong></td></tr></tbody></table><h2 id="延伸閱讀" tabindex="-1">延伸閱讀 <a class="header-anchor" href="#延伸閱讀" aria-label="Permalink to &quot;延伸閱讀&quot;">​</a></h2><ul><li><p><strong>事件驅動架構（Event-Driven Architecture）</strong></p><ul><li><a href="https://aws.amazon.com/what-is/eda/" target="_blank" rel="noreferrer">AWS：What is Event-Driven Architecture?</a></li></ul></li><li><p><strong>訊息服務怎麼選：SQS / SNS / EventBridge（與 Amazon MQ）</strong></p><ul><li><a href="https://docs.aws.amazon.com/decision-guides/latest/sns-or-sqs-or-eventbridge/sns-or-sqs-or-eventbridge.html" target="_blank" rel="noreferrer">AWS 決策指南：Amazon SQS, SNS, or EventBridge?</a></li><li><a href="https://hyuyu1544.medium.com/aws-saa-sqs-sns-aws-mq-kinesis-streams-%E6%AF%94%E8%BC%83-f8d05bbed6fb" target="_blank" rel="noreferrer">SQS｜SNS｜AWS MQ｜Kinesis 比較</a></li></ul></li><li><p><a href="https://www.enterpriseintegrationpatterns.com/" target="_blank" rel="noreferrer">Enterprise Integration Patterns</a> — Gregor Hohpe。訊息式架構的經典。</p></li></ul>`,37)])])}const c=s(e,[["render",o]]);export{h as __pageData,c as default};
